const e=JSON.parse(`{"key":"v-16707012","path":"/vanblog/Windows%E8%AE%BE%E7%BD%AE%E5%B0%8F%E9%B9%A4%E5%8F%8C%E6%8B%BC%E8%BE%93%E5%85%A5%E6%B3%95.html","title":"简介","lang":"zh-CN","frontmatter":{"description":"简介 拼音输入法应该是年轻人用的最多的输入法了，使用简单方便，依托各大输入法强大的词库联想功能，大大提高了打字效率。但是为了追求极致的打字速度，很多人还会纠结使用9键还是26键快，各执一词谁也说服不了谁。但其实大家用的拼音输入法基本都是全拼输入法，在不借助联想功能的情况下需要完整敲击拼音的每个字母才能录入文字，事实上还有另一种拼音输入法以减少击键次数来达到提升打字速度的目的，也是我们今天的主角——双拼输入法。 image.png 双拼输入法是使用两个字母对汉字进行编码的方案，第一个字母表示声母，第二字母表示韵母，也就是说任何一个汉字使用两次敲击就可以打出，相比全拼在按键次数上有明显优势，并且上手难度也比五笔输入法小得多，熟悉全拼的人可以很快入门。 双拼输入法也有很多种编码方案，如小鹤双拼、自然码双拼等，大家可根据喜好自行选择一种即可。本人使用的是小鹤双拼，其键位图如上图所示。 小鹤双拼官网：https://www.flypy.com/","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/vanblog/Windows%E8%AE%BE%E7%BD%AE%E5%B0%8F%E9%B9%A4%E5%8F%8C%E6%8B%BC%E8%BE%93%E5%85%A5%E6%B3%95.html"}],["meta",{"property":"og:site_name","content":"Kevin2li's Blog"}],["meta",{"property":"og:title","content":"简介"}],["meta",{"property":"og:description","content":"简介 拼音输入法应该是年轻人用的最多的输入法了，使用简单方便，依托各大输入法强大的词库联想功能，大大提高了打字效率。但是为了追求极致的打字速度，很多人还会纠结使用9键还是26键快，各执一词谁也说服不了谁。但其实大家用的拼音输入法基本都是全拼输入法，在不借助联想功能的情况下需要完整敲击拼音的每个字母才能录入文字，事实上还有另一种拼音输入法以减少击键次数来达到提升打字速度的目的，也是我们今天的主角——双拼输入法。 image.png 双拼输入法是使用两个字母对汉字进行编码的方案，第一个字母表示声母，第二字母表示韵母，也就是说任何一个汉字使用两次敲击就可以打出，相比全拼在按键次数上有明显优势，并且上手难度也比五笔输入法小得多，熟悉全拼的人可以很快入门。 双拼输入法也有很多种编码方案，如小鹤双拼、自然码双拼等，大家可根据喜好自行选择一种即可。本人使用的是小鹤双拼，其键位图如上图所示。 小鹤双拼官网：https://www.flypy.com/"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-05-22T06:31:47.000Z"}],["meta",{"property":"article:author","content":"Kevin2li"}],["meta",{"property":"article:modified_time","content":"2023-05-22T06:31:47.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"简介\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2023-05-22T06:31:47.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Kevin2li\\",\\"url\\":\\"https://blog.kevin2li.top\\"}]}"]]},"headers":[],"git":{"createdTime":1684730003000,"updatedTime":1684737107000,"contributors":[{"name":"kevin2li","email":"kevin2li@qq.com","commits":3}]},"readingTime":{"minutes":1.64,"words":493},"filePathRelative":"vanblog/Windows设置小鹤双拼输入法.md","localizedDate":"2023年5月22日","excerpt":"<h1> 简介</h1>\\n<p>拼音输入法应该是年轻人用的最多的输入法了，使用简单方便，依托各大输入法强大的词库联想功能，大大提高了打字效率。但是为了追求极致的打字速度，很多人还会纠结使用9键还是26键快，各执一词谁也说服不了谁。但其实大家用的拼音输入法基本都是全拼输入法，在不借助联想功能的情况下需要完整敲击拼音的每个字母才能录入文字，事实上还有另一种拼音输入法以减少击键次数来达到提升打字速度的目的，也是我们今天的主角——双拼输入法。</p>\\n<figure><img src=\\"https://minio.kevin2li.top/image-bed/vanblog/img/b178bdd410413eb88664238e11750a15.image.png\\" alt=\\"image.png\\" tabindex=\\"0\\" loading=\\"lazy\\"><figcaption>image.png</figcaption></figure>\\n<p>双拼输入法是使用两个字母对汉字进行编码的方案，第一个字母表示声母，第二字母表示韵母，也就是说任何一个汉字使用两次敲击就可以打出，相比全拼在按键次数上有明显优势，并且上手难度也比五笔输入法小得多，熟悉全拼的人可以很快入门。</p>\\n<p>双拼输入法也有很多种编码方案，如小鹤双拼、自然码双拼等，大家可根据喜好自行选择一种即可。本人使用的是小鹤双拼，其键位图如上图所示。</p>\\n<p>小鹤双拼官网：<a href=\\"https://www.flypy.com/\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">https://www.flypy.com/</a></p>\\n","autoDesc":true}`);export{e as data};
